|en
|year=1967
|author=w:Barbara Sleigh
|title=w:Jessamy
|year_published=1993
|location=Sevenoaks, Kent
|publisher=Bloomsbury
|isbn=0 340 19547 9
|page=84
|url=
|passage=The old man heaved himself from the chair, seized Jessamy by her pinafore frill and '''marched''' her to the house.
}}
